# NL ZEH.  Zaandam - Enkhuizen
with detail = 2 {
    let ze = path("d2.nl.zeh");

    with railway = :first :double :cat:dc15 :pax {
        with link = "line.nl.ZEH" {
            track(ze[:zaa.ye, :zaa.ye + 15.51km]);
            line_label(:right:nw, ze[:zaa.ye + 15.5km] >> 0.5mt, "ZEH");
            track(ze[:zaa.ye + 15.49km, :hoo.yh]);
        }

        with link = "point.nl.Hoorn" {
            track(ze[:hoo.yh, :hoo.ym]);
            statdot(ze[:hoo]);
            slabel(:nw, ze[:hoo] + (0dt, 1dt), "Hoorn");
        }

        with link = "line.nl.ZEH" {
            track(
                    ze[:hoo.ym - 0.1dl, :hoo.ym]
                ..  ze[:hoo.xm + 1mt, :hke] >> 0.5mt << 0.5md
            );
        }
    }

    with railway = :first :cat:dc15 :pax {
        with link = "line.nl.ZEH" {
            track(ze[:hke, :hke + 5.71km]);
            line_label(:right:nw, ze[:hke + 5.7km] >> 0.5mt, "ZEH");
            track(ze[:hke + 5.69km, :enk]);
        }

        with link = "point.nl.Enkhuizen" {
            statdot(ze[:enk]);
            slabel(:right, ze[:enk] + (1.5dt, 1dt), "Enkhuizen");
        }
    }
}


# NL ZSG.  Zaandam - Amsterdam Singelgracht
with detail = 2 {
    let zs = path("d2.nl.zsg");

    with railway = :first :double :cat:dc15 :pax {
        track(zs[:zaa, :asl.yz]);
        track(zs[:asl.yz, :asl.yr]);
        track(zs[:asl.yr, :sin.yz]);
    }
}
